def filter_single_token_facts(model, dataset, max_examples=200):
    """Filter to facts where the target object is a single token."""
    filtered = []
    for i, ex in enumerate(dataset):
        if len(filtered) >= max_examples:
            break
        # Extract prompt and target - CounterFact has various formats
        if isinstance(ex.get("requested_rewrite"), dict):
            rw = ex["requested_rewrite"]
            prompt = rw.get("prompt", "").replace("{}", rw.get("subject", ""))
            target = rw.get("target_true", {})
            if isinstance(target, dict):
                target_str = target.get("str", "")
            else:
                target_str = str(target)
        elif "prompt" in ex and "target_true" in ex:
            prompt = ex["prompt"]
            target_str = ex["target_true"]
        else:
            continue

        if not prompt or not target_str:
            continue

        # Check single token
        target_tokens = model.to_tokens(" " + target_str, prepend_bos=False)[0]
        if len(target_tokens) == 1:
            filtered.append({
                "prompt": prompt,
                "target": target_str,
                "target_token": target_tokens[0].item(),
                "index": i,
            })

    print(f"Filtered to {len(filtered)} single-token-target facts")
    return filtered

